const body = $input.first().json.body || $input.first().json;
const tz = 'Asia/Kolkata';
const requested = body.requested_datetime_iso || body.requested_datetime || '';
const duration = parseInt(body.duration_minutes || '30', 10);
const service = body.service || 'Consultation';
const callId = body.call_id || '';
const bufferMin = 10;
if (!requested) return [{ json: { error:'missing_requested_datetime' } }];
const start = new Date(requested);
if (isNaN(start.getTime())) return [{ json: { error:'bad_iso', got: requested } }];
const end = new Date(start.getTime() + duration*60000);
const dtf = new Intl.DateTimeFormat('en-GB', { timeZone: tz, weekday:'short', hour:'numeric', minute:'numeric', hour12:false });
const parts = Object.fromEntries(dtf.formatToParts(start).map(p => [p.type, p.value]));
const weekday = parts.weekday;
const hourMin = parseInt(parts.hour,10)*60 + parseInt(parts.minute,10);
const isSunday = weekday === 'Sun';
const outsideHours = isSunday || hourMin < 10*60 || (hourMin + duration) > 19*60;
const windowStart = new Date(start.getTime() - bufferMin*60000).toISOString();
const windowEnd = new Date(end.getTime() + bufferMin*60000).toISOString();
const calId = '9e31eddd03011a49802170cdb7228dd24099675b0bd216060ba080d93e714e42@group.calendar.google.com';
return [{ json: { call_id: callId, service, duration, requested_iso: start.toISOString(), end_iso: end.toISOString(), window_start: windowStart, window_end: windowEnd, weekday, outside_hours: outsideHours, cal_id: calId } }];

const p = $('Parse Input').item.json;
const fb = $input.first().json;
const cal = (fb.calendars || {})[p.cal_id] || {};
const busy = cal.busy || [];
const isFree = busy.length === 0;
if (isFree) {
  return [{ json: { available: true, requested_slot: p.requested_iso, duration_minutes: p.duration, service: p.service, call_id: p.call_id, alternatives: [] } }];
}
const tz = 'Asia/Kolkata';
const dtf = new Intl.DateTimeFormat('en-GB', { timeZone: tz, weekday:'short', hour:'numeric', minute:'numeric', hour12:false });
function inHours(date, d) {
  const parts = Object.fromEntries(dtf.formatToParts(date).map(x => [x.type, x.value]));
  if (parts.weekday === 'Sun') return false;
  const m = parseInt(parts.hour,10)*60 + parseInt(parts.minute,10);
  return m >= 10*60 && (m+d) <= 19*60;
}
const alts = [];
let probe = new Date(p.requested_iso);
for (let i=1; i<=48 && alts.length < 3; i++) {
  probe = new Date(probe.getTime() + 30*60000);
  if (!inHours(probe, p.duration)) continue;
  alts.push(probe.toISOString());
}
return [{ json: { available: false, requested_slot: p.requested_iso, duration_minutes: p.duration, service: p.service, call_id: p.call_id, alternatives: alts, reason: 'busy' } }];

